import 'dotenv/config';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import OpenAI from 'openai';

const s3 = new S3Client\({
  region: 'auto',
  endpoint: 'https://' + process.env.R2_ACCOUNT_ID + '.r2.cloudflarestorage.com',
  credentials: {
    accessKeyId: process.env.R2_ACCESS_KEY_ID,
    secretAccessKey: process.env.R2_SECRET_ACCESS_KEY,
  },
}\);
const openai = new OpenAI\({ apiKey: process.env.OPENAI_KEY }\);
const BASE = \(process.env.R2_PUBLIC_BASE_URL || 'https://assets.genmytee.com'\).replace\(/\\/+$/, ''\);
const BUCKET = process.env.R2_BUCKET || 'genmytee-printful';

console.log\('Generating Koi Japonés...'\);
const result = await openai.images.generate\({
  model: 'gpt-image-1',
  prompt: 'Pez koi rojo y dorado nadando entre ondas y flores de loto blancas, estilo tinta japonesa tradicional',
  size: '1024x1024',
}\);

const imageData = result.data[0];
let buffer;
if \(imageData.b64_json\) {
  buffer = Buffer.from\(imageData.b64_json, 'base64'\);
} else if \(imageData.url\) {
  const resp = await fetch\(imageData.url, { signal: AbortSignal.timeout\(30000\) }\);
  buffer = Buffer.from\(await resp.arrayBuffer\(\)\);
}

const key = 'images/gallery-koi-japones.png';
await s3.send\(new PutObjectCommand\({
  Bucket: BUCKET,
  Key: key,
  Body: buffer,
  ContentType: 'image/png',
  CacheControl: 'public, max-age=31536000, immutable',
}\)\);

const url = BASE + '/' + encodeURI\(key\);
console.log\('Uploaded:', url\);

// Update curated-designs.json
import { readFileSync, writeFileSync } from 'node:fs';
const file = 'data/curated-designs.json';
const data = JSON.parse\(readFileSync\(file, 'utf8'\)\);
const koi = data.designs.find\(d => d.id === 'koi-japones'\);
if \(koi\) {
  koi.image_url = url;
  writeFileSync\(file, JSON.stringify\(data, null, 2\) + '\\n', 'utf8'\);
  console.log\('Updated curated-designs.json'\);
} else {
  console.log\('Design not found in JSON'\);
}
